/**
 * TinyMCE 8 Drawing Plugin  v2.1.0
 *
 * Opens drawing.html in a TinyMCE URL dialog with native footer buttons.
 * Communication between the plugin and the iframe uses window.postMessage.
 *
 * Messages FROM drawing.html → plugin:
 *   { type: 'tdp-ready' }              — page loaded; plugin sends tdp-init
 *   { type: 'tdp-done', src: <url> }   — canvas exported; plugin inserts <img>
 *
 * Messages FROM plugin → drawing.html:
 *   { type: 'tdp-init', imageSrc: <url|null> }  — optional image to pre-load
 *   { type: 'tdp-export' }                       — footer "Insert" button clicked
 *
 * Usage:
 *   tinymce.init({
 *     plugins:  'drawing',
 *     toolbar:  'drawing',
 *     images_upload_handler: async (blobInfo, progress) => { ... return url; }
 *   });
 *
 * Place drawing.html in the same directory as plugin.js, or set:
 *   drawing_page_url: '/path/to/drawing.html'
 */
(function () {
  'use strict';

  tinymce.PluginManager.add('drawing', function (editor) {

    function openDrawingDialog() {
      const pluginUrl = editor.options.get('drawing_page_url') ||
                        (tinymce.PluginManager.urls['drawing'] + '/drawing.html');

      const selectedNode = editor.selection.getNode();
      const initialSrc   = (selectedNode && selectedNode.nodeName === 'IMG')
                           ? selectedNode.src : null;

      let dialogApi  = null;
      let iframeReady = false;

      // Send a message to the iframe
      function sendToIframe(msg) {
        // The iframe TinyMCE renders is .tox-urldialogiframe
        const iframe = document.querySelector('.tox-dialog__body-iframe iframe');
        if (iframe && iframe.contentWindow) {
          iframe.contentWindow.postMessage(msg, '*');
        }
      }

      // Handle messages from the iframe
      function onMessage(evt) {
        const data = evt.data;
        if (!data || typeof data.type !== 'string') return;

        if (data.type === 'tdp-ready') {
          iframeReady = true;
          sendToIframe({ type: 'tdp-init', imageSrc: initialSrc });
          return;
        }

        if (data.type === 'tdp-cancel') {
          window.removeEventListener('message', onMessage);
          if (dialogApi) dialogApi.close();
          return;
        }

        if (data.type === 'tdp-done') {
          window.removeEventListener('message', onMessage);

          const src = data.src;
          if (!src) return;

          // Close dialog first so the editor regains focus before insertion
          if (dialogApi) dialogApi.close();

          if (src.startsWith('data:') &&
              typeof editor.options.get('images_upload_handler') === 'function') {
            // Upload the data URI blob via the configured handler
            fetch(src)
              .then(r => r.blob())
              .then(blob => {
                const filename = `drawing-${Date.now()}.png`;
                const blobUri  = URL.createObjectURL(blob);
                const blobInfo = {
                  id:       () => `blobid${Date.now()}`,
                  name:     () => filename,
                  filename: () => filename,
                  blob:     () => blob,
                  base64:   () => null,
                  blobUri:  () => blobUri,
                };
                return editor.options.get('images_upload_handler')(blobInfo, () => {})
                  .then(url => { URL.revokeObjectURL(blobUri); return url; });
              })
              .then(url => editor.insertContent(`<img src="${url}" alt="Drawing">`))
              .catch(err => {
                console.error('[drawing-plugin] upload error', err);
                editor.insertContent(`<img src="${src}" alt="Drawing">`);
              });
          } else {
            editor.insertContent(`<img src="${src}" alt="Drawing">`);
          }
        }
      }

      window.addEventListener('message', onMessage);

      dialogApi = editor.windowManager.openUrl({
        title:  'Drawing',
        url:    pluginUrl,
        width:  900,
        height: 650,
        buttons: [
          {
            type: 'cancel',
            name: 'cancel',
            text: 'Cancel',
          },
          {
            type:    'custom',
            name:    'insert',
            text:    'Insert Drawing',
            primary: true,
          },
        ],
        onAction: (api, details) => {
          if (details.name === 'insert') {
            // Tell the iframe to export; it will reply with tdp-done
            sendToIframe({ type: 'tdp-export' });
          }
        },
        onClose: () => {
          window.removeEventListener('message', onMessage);
        },
      });
    }

    editor.ui.registry.addButton('drawing', {
      icon:     'edit-block',
      tooltip:  'Insert Drawing',
      onAction: openDrawingDialog,
    });

    editor.ui.registry.addMenuItem('drawing', {
      icon:     'edit-block',
      text:     'Drawing…',
      onAction: openDrawingDialog,
    });

    return {
      getMetadata: () => ({
        name:    'Drawing Plugin',
        url:     'https://github.com/your-org/tinymce-drawing-plugin',
        version: '2.1.0',
      }),
    };
  });

})();
